    "content": {
      "code": "function coor_diag(Squares,y,x) {
    let allowed_positions = [];
    let i = 1;
    while ((y - i >= 0) && (x + i < 8)) {
        if(typeof Squares[y - i][x + i] === 'object'){
            if ( Squares[y - i][x + i].color === Squares[y][x].color) {
                break;
            }
            else{
                allowed_positions.push([y - i, x + i]);
                break;
            };
        }
        else{            allowed_positions.push([y - i, x + i])
        }
        i++;
    }
    i = 1;
    while ((y - i >= 0) && (x - i >= 0)) {
        if(typeof Squares[y - i][x - i] === 'object'){
            if ( Squares[y - i][x - i].color === Squares[y][x].color) {
                break;
            }
            else{
                allowed_positions.push([y - i, x - i]);
                break;
            };
        }
        else{            allowed_positions.push([y - i, x - i]);
        }
        i++;
    }
    i = 1;
    while ((y + i < 8) && (x + i < 8)) {
        if(typeof Squares[y + i][x + i] === 'object'){
            if ( Squares[y + i][x + i].color === Squares[y][x].color) {
                break;
            }
            else{
                allowed_positions.push([y + i, x + i]);
                break;
            };
        }
        else{            allowed_positions.push([y + i, x + i]);
        }
        i++;
    }
    i = 1;
    while ((y + i < 8) && (x - i >= 0)) {
        if(typeof Squares[y + i][x - i] === 'object'){
            if ( Squares[y + i][x - i].color === Squares[y][x].color) {
                break;
            }
            else{
                allowed_positions.push([y + i, x - i]);
                break;
            };
        }
        else{            allowed_positions.push([y + i, x - i]);
        }
        i++;
    }
    return allowed_positions
