content.code:
* {
  box-sizing: border-box;
}

body {
  margin: 0;
  min-height: 100vh;
  background: radial-gradient(circle at top left, rgba(255, 215, 135, 0.06), transparent 20%),
    radial-gradient(circle at bottom right, rgba(196, 165, 109, 0.08), transparent 18%),
    linear-gradient(180deg, #090b10 0%, #12171f 100%);
  color: #e5e7eb;
}

button {
  font-family: inherit;
}

.app-shell {
  min-height: 100vh;
  display: flex;
  justify-content: center;
  align-items: center;
  padding: 24px 0;
}

.app-main {
  width: min(1040px, calc(100% - 32px));
  display: flex;
  justify-content: center;
}

.page-center {
  width: 100%;
  margin: 0 auto;
}

.winner-card {
  max-width: 720px;
  width: 100%;
  padding: 38px;
  border-radius: 18px;
  background: rgba(21, 28, 37, 0.94);
  box-shadow: 0 32px 92px rgba(0, 0, 0, 0.28);
  border: 1px solid rgba(229, 231, 235, 0.08);
}

.section-title {
  font-size: clamp(2rem, 3vw, 3rem);
  line-height: 1.04;
  margin: 0 0 20px;
  color: #f8fafc;
  letter-spacing: -0.03em;
}

.section-copy {
  color: #cbd5e1;
  font-size: 1rem;
  line-height: 1.9;
  margin: 0 0 28px;
}

.feature-grid {
  display: grid;
  gap: 18px;
  margin-top: 24px;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
}

.feature-card {
  padding: 22px;
  border-radius: 14px;
  background: rgba(255, 255, 255, 0.04);
  border: 1px solid rgba(255, 255, 255, 0.07);
}

.button-secondary {
  appearance: none;
  border: none;
  border-radius: 12px;
  cursor: pointer;
  padding: 16px 30px;
  font-size: 1rem;
  font-weight: 700;
  letter-spacing: 0.02em;
  transition: background-color 0.2s ease, transform 0.15s ease, opacity 0.15s ease;
}

.button-primary {
  background-color: #b88b4a;
  color: #0f0d08;
}

.button-secondary {
  background-color: rgba(229, 231, 235, 0.08);
  color: #e5e7eb;
  border: 1px solid rgba(229, 231, 235, 0.14);
}

.status-panel {
  display: grid;
  gap: 16px;
  margin: 26px 0;
}

.status-card {
  padding: 20px 22px;
  border-radius: 14px;
  background: rgba(255, 255, 255, 0.04);
  border: 1px solid rgba(255, 255, 255, 0.08);
}

.button-group {
  display: flex;
  gap: 16px;
  flex-wrap: wrap;
  margin-top: 28px;
}

.Board-shell {
    min-height: 100vh;
    background: radial-gradient(circle at top left, rgba(148, 163, 184, 0.12), transparent 25%),
      linear-gradient(180deg, #0b1220 0%, #111827 100%);
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 28px;
}

.Board-container {
    width: min(1200px, 100%);
    display: grid;
    grid-template-columns: 320px minmax(620px, 1fr);
    gap: 28px;
    align-items: start;
}

.Board-sidebar {
    background: rgba(15, 23, 42, 0.95);
    border-radius: 32px;
    padding: 28px;
    color: #e2e8f0;
    box-shadow: 0 28px 90px rgba(15, 23, 42, 0.35);
    display: flex;
    flex-direction: column;
    gap: 24px;
}

.Board-sidebar__card {
    display: grid;
    gap: 16px;
}

.Board-sidebar__label {
    margin: 0;
    color: #94a3b8;
    font-size: 0.95rem;
}

.Board-sidebar__value {
    margin: 0;
    font-size: 1.05rem;
    color: #f8fafc;
    font-weight: 600;
}

.Board-sidebar__status {
    display: inline-flex;
    align-items: center;
    justify-content: space-between;
    gap: 10px;
}

.Clock-panel {
    display: grid;
    gap: 18px;
}

.Clock-panel__item {
    display: grid;
    gap: 10px;
}

.Clock-panel__title {
    color: #94a3b8;
    font-size: 0.95rem;
}

.Board-button {
    margin-top: auto;
    padding: 14px 18px;
    border-radius: 999px;
    border: none;
    background: linear-gradient(90deg, #f97316 0%, #ea580c 100%);
    color: #fff;
    font-weight: 700;
    cursor: pointer;
    transition: transform 0.2s ease, box-shadow 0.2s ease;
}

.Board-board-box {
    background: linear-gradient(180deg, rgba(255,255,255,0.05), rgba(15,23,42,0.15));
    border: 1px solid rgba(148, 163, 184, 0.15);
